#!/usr/bin/env python3
# Generated By: Claude Code (Claude Opus 4.6)
"""Count non-test, non-generated source lines per language.

Feeds the Phase 1 tier decision in the c4-reverse-engineer skill. Tier boundaries:
    < 3,000  → small  (direct reads only)
    3k–15k   → medium (hybrid, 2 subagents)
    > 15,000 → large  (3 subagents)

Usage:
    python -m scripts.count_source_lines [root]

Defaults to the current working directory. Prints a per-language breakdown and the total,
then recommends a tier.
"""

from __future__ import annotations

import argparse
import sys
from pathlib import Path

# Maps language name → set of file extensions.
LANGUAGE_EXTENSIONS: dict[str, set[str]] = {
    "Python": {".py"},
    "TypeScript": {".ts", ".tsx"},
    "JavaScript": {".js", ".jsx", ".mjs", ".cjs"},
    "Go": {".go"},
    "Rust": {".rs"},
    "Java": {".java"},
    "Kotlin": {".kt", ".kts"},
    "C": {".c", ".h"},
    "C++": {".cpp", ".cc", ".cxx", ".hpp", ".hh"},
    "C#": {".cs"},
    "Ruby": {".rb"},
    "PHP": {".php"},
    "Swift": {".swift"},
    "Shell": {".sh", ".bash", ".zsh"},
    "Lua": {".lua"},
    "Elixir": {".ex", ".exs"},
    "Haskell": {".hs"},
    "Scala": {".scala"},
    "Dart": {".dart"},
    "R": {".r", ".R"},
    "Julia": {".jl"},
    "OCaml": {".ml", ".mli"},
}

# Directory names to skip entirely.
SKIP_DIRS: set[str] = {
    ".git",
    ".hg",
    ".svn",
    "node_modules",
    "venv",
    ".venv",
    "env",
    ".env",
    "__pycache__",
    "build",
    "dist",
    "target",
    "out",
    ".tox",
    ".pytest_cache",
    ".mypy_cache",
    ".ruff_cache",
    ".next",
    ".nuxt",
    "vendor",
    "third_party",
    "third-party",
    "external",
    "deps",
    "coverage",
    ".coverage",
    "htmlcov",
    "site-packages",
    ".idea",
    ".vscode",
    ".claude",
}

# Test file/directory heuristics — excluded from the count.
TEST_DIR_NAMES: set[str] = {"tests", "test", "__tests__", "spec", "specs", "testdata"}
TEST_FILE_PREFIXES: tuple[str, ...] = ("test_",)
TEST_FILE_SUFFIXES: tuple[str, ...] = ("_test.py", "_test.go", ".test.ts", ".test.tsx", ".test.js", ".spec.ts", ".spec.tsx", ".spec.js")

# Generated-file markers checked by reading the first few lines.
# Must be specific enough to avoid matching author attribution lines
# (e.g., "Generated By: Claude Code" in a file header is an attribution,
# not a machine-output marker).
GENERATED_MARKERS: tuple[str, ...] = (
    "do not edit",
    "do not modify",
    "auto-generated",
    "autogenerated",
    "@generated",
    "code generated by the protocol buffer compiler",
    "this file was automatically generated",
    "this file is generated",
)


def is_test_path(path: Path, root: Path) -> bool:
    try:
        rel_parts = path.relative_to(root).parts
    except ValueError:
        rel_parts = path.parts
    for part in rel_parts[:-1]:
        if part.lower() in TEST_DIR_NAMES:
            return True
    name = path.name
    if any(name.startswith(p) for p in TEST_FILE_PREFIXES):
        return True
    if any(name.endswith(s) for s in TEST_FILE_SUFFIXES):
        return True
    return False


def is_generated(path: Path) -> bool:
    try:
        with path.open("r", encoding="utf-8", errors="replace") as f:
            head = "".join(next(f, "") for _ in range(5)).lower()
    except OSError:
        return False
    return any(marker in head for marker in GENERATED_MARKERS)


def extension_language() -> dict[str, str]:
    ext_to_lang: dict[str, str] = {}
    for lang, exts in LANGUAGE_EXTENSIONS.items():
        for ext in exts:
            ext_to_lang[ext] = lang
    return ext_to_lang


def count_lines(path: Path) -> int:
    try:
        with path.open("rb") as f:
            return sum(1 for _ in f)
    except OSError:
        return 0


def walk(root: Path) -> dict[str, tuple[int, int]]:
    ext_to_lang = extension_language()
    totals: dict[str, tuple[int, int]] = {}

    for dirpath, dirnames, filenames in root_walk(root):
        dirnames[:] = [d for d in dirnames if d not in SKIP_DIRS and not d.startswith(".")]
        for fname in filenames:
            path = Path(dirpath) / fname
            ext = path.suffix.lower()
            lang = ext_to_lang.get(ext)
            if not lang:
                continue
            if is_test_path(path, root):
                continue
            if is_generated(path):
                continue
            lines = count_lines(path)
            files, prev_lines = totals.get(lang, (0, 0))
            totals[lang] = (files + 1, prev_lines + lines)
    return totals


def root_walk(root: Path):
    import os

    for dirpath, dirnames, filenames in os.walk(root):
        yield dirpath, dirnames, filenames


def recommend_tier(total_lines: int) -> str:
    if total_lines < 3_000:
        return "small  (< 3k lines) - direct reads for everything; skip Phase 2"
    if total_lines < 15_000:
        return "medium (3k-15k lines) - hybrid; 2 subagents in Phase 2"
    return "large  (> 15k lines) - subagent-heavy; 3 subagents in Phase 2"


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("root", nargs="?", default=".", help="Project root (default: cwd)")
    args = parser.parse_args(argv)

    root = Path(args.root).resolve()
    if not root.is_dir():
        print(f"error: not a directory: {root}", file=sys.stderr)
        return 1

    totals = walk(root)
    if not totals:
        print(f"No source files found under {root}")
        return 0

    total_lines = sum(lines for _, lines in totals.values())
    total_files = sum(files for files, _ in totals.values())

    print(f"Project: {root}")
    print()
    print(f"{'Language':<14} {'Files':>8} {'Lines':>10}")
    print(f"{'-' * 14} {'-' * 8} {'-' * 10}")
    for lang in sorted(totals, key=lambda k: totals[k][1], reverse=True):
        files, lines = totals[lang]
        print(f"{lang:<14} {files:>8,} {lines:>10,}")
    print(f"{'-' * 14} {'-' * 8} {'-' * 10}")
    print(f"{'TOTAL':<14} {total_files:>8,} {total_lines:>10,}")
    print()
    print(f"Tier: {recommend_tier(total_lines)}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
